-- Protected By Meknoyu Lua --
local _Meknoyu_Block = ""
local _Meknoyu_Dec = function(s)
    local out = {}
    for i = 1, #s, 2 do
        local hex = s:sub(i, i+1)
        local num = tonumber(hex, 16)
        if num then
            local decoded = (num - 17) % 256
            if decoded < 0 then decoded = decoded + 256 end
            table.insert(out, string.char(decoded))
        end
    end
    return table.concat(out)
end
local exec = loadstring or load
if exec then
    local chunk, err = exec(_Meknoyu_Dec(_Meknoyu_Block))
    if chunk then
        local success, runErr = pcall(chunk)
        if not success then
            warn("Meknoyu Lua Runtime Error: " .. tostring(runErr))
        end
    else
        warn("Meknoyu Lua Compilation Error: " .. tostring(err))
    end
else
    print("Meknoyu Lua Support: executor 'loadstring' is not available or disabled.")
end
